const item = $input.first();
const mentorado = item.json.mentorado;
const message = item.json.message;
const content = item.json.content || message.content;

if (!mentorado || !message || !content) {
  throw new Error('Dados incompletos: mentorado, message ou content ausente');
}

const EQUIPE_NOMES = ['Heitor', 'Hugo Nicchio', 'Hugo', 'Lara', 'Kaique Rodrigues', 'Kaique', 'Queila Trizotti', 'Queila', 'Suporte CASE', 'Heitor Sarmenghi', 'Heitor Estrategista', 'Queila - Business', 'Gabriel Rosseto'];

const EQUIPE_APELIDOS = {
  'Heitor': 'Heitor', 'Hugo Nicchio': 'Hugo', 'Hugo': 'Hugo', 'Lara': 'Lara',
  'Kaique Rodrigues': 'Kaique', 'Kaique': 'Kaique', 'Queila Trizotti': 'Queila',
  'Queila': 'Queila', 'Queila - Business': 'Queila', 'Suporte CASE': 'Suporte',
  'Heitor Sarmenghi': 'Heitor', 'Heitor Estrategista': 'Heitor', 'Gabriel Rosseto': 'Gabriel'
};

function ehEquipe(senderName) {
  if (!senderName) return false;
  const nome = senderName.toLowerCase();
  return EQUIPE_NOMES.some(membro => nome.includes(membro.toLowerCase()));
}

function identificarAutor(senderName) {
  if (!ehEquipe(senderName)) return null;
  for (const [nomeCompleto, apelido] of Object.entries(EQUIPE_APELIDOS)) {
    if (senderName.includes(nomeCompleto) || senderName.includes(apelido)) return apelido;
  }
  return senderName.split(' ')[0];
}

function limparTexto(texto) {
  if (!texto) return '';
  return texto.replace(/^\[~?[^\]]+\]\s*:?\s*/g, '').replace(/\u200e<Mensagem editada>.*$/i, '').replace(/@~[^\s]+\s*/g, '').replace(/\u200e<anexado:.*?>/g, '').replace(/\[\d{2}\/\d{2}\/\d{4},\s*\d{2}:\d{2}:\d{2}\]/g, '').trim();
}

// MELHORADO: mais restritivo sobre o que eh pergunta real
function ehPerguntaReal(texto, isEquipe) {
  const limpo = limparTexto(texto).toLowerCase();
  // Muito curto = nao eh pergunta real
  if (limpo.length < 20) return false;
  // Confirmacoes / saudacoes com ? nao sao perguntas
  if (limpo.match(/^(ok|valeu|obrigad|show|boa|blz|tmj|beleza|perfeito|otimo|certo|entendi|sim|nao|pode|claro|bora|vamos|combinado|fechou|pode ser|ne|neh|ta bom)\b/i)) return false;
  // Perguntas retoricas "vai ser ne?", "vamos ne?"
  if (limpo.match(/\b(ne|neh|hein)\?*\s*$/i)) return false;
  // Precisa ter ? ou palavra interrogativa
  const temInterrogacao = limpo.includes('?');
  const temPalavraInterrogativa = limpo.match(/\b(pode|consegue|tem como|onde|como|qual|quando|quem|por que|porque|explicar|cadûˆ|cade)\b/i);
  if (!temInterrogacao && !temPalavraInterrogativa) return false;
  // ? com conteudo curto demais = provavelmente confirmacao
  if (temInterrogacao && limpo.replace(/[?!.]/g, '').trim().length < 15) return false;
  return true;
}

// NOVO: detecta se eh mensagem descartavel (saudacao, confirmacao, emoji)
function ehDescartavel(texto) {
  const limpo = limparTexto(texto).toLowerCase();
  if (limpo.length < 10) return true;
  if (/^(bom dia|boa tarde|boa noite|oi|oie|oiee|ola|hey|eai|fala|\ud83d|\ud83e|\u2764|ok|sim|nao|valeu|obrigad|show|beleza|perfeito|blz|tmj|combinado|fechou|massa|top|amem|amen)\b/i.test(limpo)) return true;
  // So emojis/figurinhas
  if (limpo.replace(/[\u{1F000}-\u{1FFFF}\s]/gu, '').length < 3) return true;
  return false;
}

const txtLower = content.toLowerCase();
const txtLimpo = limparTexto(content);
const isEquipe = ehEquipe(message.sender_name);
const autor = identificarAutor(message.sender_name);
const descartavel = ehDescartavel(content);

const classificacao = {
  eh_equipe: isEquipe,
  autor_identificado: autor,
  eh_pergunta_real: ehPerguntaReal(content, isEquipe),
  eh_descartavel: descartavel,
  tem_interrogacao: content.includes('?'),
  tipo_interacao: descartavel ? 'social' : 'mensagem',
  categoria: descartavel ? 'saudacao' : 'geral',
  indicadores: {
    pediu_material: /\b(pode enviar|tem o material|cadûˆ o link|cade o link|onde estûÀ|onde esta|preciso do|link do|me manda)\b/i.test(txtLower),
    pediu_call: /\b(marcar call|agenda call|reuniûÈo|reuniao|vamos conversar|podemos conversar)\b/i.test(txtLower),
    pediu_indicacao: /\b(indicaûÏûÈo|indicacao|indica|conhece alguûˋm|conhece alguem|tem alguûˋm|tem alguem)\b/i.test(txtLower),
    executou_acao: /\b(fiz|gravei|postei|publiquei|criei|lancei|enviei|consegui fazer|finalizei|realizei|dei aula|apresentei|terminei|entreguei|executei|implementei|concluûÙ|conclui)\b/i.test(txtLower),
    planejou_acao: /\b(vou fazer|vou gravar|vou comeûÏar|vou comecar|vou terminar|vou finalizar|pretendo|planejo|essa semana|hoje eu|amanhûÈ eu|amanha eu|prû°ximo passo|proximo passo|vou enviar|vou postar|vou criar)\b/i.test(txtLower),
    reportou_venda: /\b(vendi|vendemos|fechei|fechamos|batemos meta|recebi o pagamento|pagamento confirmado|cliente pagou)\b/i.test(txtLower) && !/\b(nûÈo recebi|nao recebi|sem pagamento|cadûˆ o pagamento|cade o pagamento|aguardando pagamento)\b/i.test(txtLower),
    mencionou_lead: /\b(lead|interessado|aplicaûÏûÈo|aplicacao|diagnû°stico|diagnostico|call marcada|to com um|tûÇ com um)\b/i.test(txtLower),
    mencionou_valores: /\d+\s*(?:leads?|conversûçes?|conversoes?|vendas?|seguidores?|alcance|visualizaûÏûçes|visualizacoes|engajamento|faturamento|r\$)/i.test(txtLower),
    publicou_conteudo: /\b(gravei|postei|publiquei|lancei o vûÙdeo|lancei o video|subiu o post|criei o carrossel|soltei o conteû¤do|soltei o conteudo)\b/i.test(txtLower),
    planejou_conteudo: /\b(vou gravar|vou postar|prû°ximo conteû¤do|proximo conteudo|calendûÀrio|calendario|editorial|vou criar)\b/i.test(txtLower),
    mencionou_dificuldade: /\b(nûÈo consigo|nao consigo|empacad|travad|dificuldade|nûÈo sei como|nao sei como|complicado|dû¤vida sobre|duvida sobre|preciso de ajuda|me ajuda|socorro|difûÙcil|dificil)\b/i.test(txtLower),
    demonstrou_travamento: /\b(travado|parado|empacado|nûÈo sai do lugar|nao sai do lugar|estagnado)\b/i.test(txtLower),
    celebrou_vitoria: /\b(consegui|deu certo|top|û°timo|otimo|amei|bafo|foda|massa|show|demais|perfeito|excelente|incrûÙvel|incrivel|adorei)\b/i.test(txtLower),
    frustrado: /\b(frustrad|desanim|cansad|desist|caiu|caûÙram|cairam|caindo|queda|despenc|pûˋssimo|pessimo|horrûÙvel|horrivel|desastre|crise)\b/i.test(txtLower),
    sinalizou_desistencia: /\b(desistir|desisti|nûÈo aguento|nao aguento|vou parar|chega)\b/i.test(txtLower),
    questionou_metodologia: /\b(nûÈo funciona|nao funciona|nûÈo estûÀ dando|nao esta dando|nûÈo acredito|nao acredito|serûÀ que vale|sera que vale)\b/i.test(txtLower)
  },
  sentimento: 'neutro',
  energia: 'normal',
  requer_resposta: false,
  requer_acao_equipe: false,
  urgencia_resposta: 'nao_urgente',
  prioridade: 'normal',
  tamanho_texto: txtLimpo.length,
  tem_emoji: /[\u{1F600}-\u{1F64F}]|[\u{1F300}-\u{1F5FF}]|[\u{1F680}-\u{1F6FF}]|[\u{1F1E0}-\u{1F1FF}]/gu.test(content),
  contexto_negocio: 'mentoria_ativa',
  score_engajamento: descartavel ? 1 : 5,
  resumo: txtLimpo.substring(0, 200),
  tags: [],
  acoes_sugeridas: []
};

// ExtraûÏûÈo de valores (vendas, faturamento, leads)
const valores_extraidos = { vendas: null, faturamento: null, leads: null, conversoes: null, ticket_medio: null };
const regexVendasQtd = /(?:vendi|vendemos|fechei|fechamos)\s*(\d+)/gi;
let matchVendas;
while ((matchVendas = regexVendasQtd.exec(txtLower)) !== null) {
  const qtd = parseInt(matchVendas[1]);
  if (qtd > 0 && qtd < 100) valores_extraidos.vendas = (valores_extraidos.vendas || 0) + qtd;
}
const regexValor = /r?\$\s*([\d.,]+)\s*(?:mil|k)?/gi;
let matchValor;
while ((matchValor = regexValor.exec(txtLower)) !== null) {
  let valor = parseFloat(matchValor[1].replace(/\./g, '').replace(',', '.'));
  valores_extraidos.faturamento = (valores_extraidos.faturamento || 0) + valor;
}
const regexLeads = /(\d+)\s*leads?/gi;
let matchLeads;
while ((matchLeads = regexLeads.exec(txtLower)) !== null) {
  const qtd = parseInt(matchLeads[1]);
  if (qtd > 0) valores_extraidos.leads = (valores_extraidos.leads || 0) + qtd;
}
classificacao.valores_extraidos = valores_extraidos;

// MenûÏûçes
const mencoes = { produtos: [], pessoas: [], ferramentas: [], processos: [] };
const ferramentas_conhecidas = ['instagram', 'facebook', 'whatsapp', 'tiktok', 'youtube', 'linkedin', 'notion', 'canva', 'capcut', 'google', 'meta'];
ferramentas_conhecidas.forEach(f => { if (txtLower.includes(f)) mencoes.ferramentas.push(f); });
classificacao.mencoes = mencoes;

// ===== CLASSIFICACAO POR TIPO (ordem de prioridade) =====
// MELHORADO: descartaveis saem direto, equipe nao gera pendencia

if (!descartavel) {
  if (classificacao.indicadores.reportou_venda) {
    classificacao.tipo_interacao = 'celebracao'; classificacao.categoria = 'vendas';
    classificacao.score_engajamento = 9; classificacao.tags.push('venda', 'resultado');
  }
  if (classificacao.indicadores.executou_acao && !classificacao.indicadores.reportou_venda) {
    classificacao.tipo_interacao = 'reporte'; classificacao.score_engajamento = 7;
    classificacao.tags.push('execucao');
  }

  // MELHORADO: duvida so gera requer_resposta se NAO eh da equipe
  if (classificacao.eh_pergunta_real && !isEquipe) {
    classificacao.tipo_interacao = 'duvida';
    classificacao.requer_resposta = true;
    classificacao.urgencia_resposta = '24h';
    classificacao.score_engajamento = 6;
    classificacao.tags.push('pergunta');
  }
  // Se equipe perguntou, eh o mentorado que precisa responder
  if (classificacao.eh_pergunta_real && isEquipe) {
    classificacao.tipo_interacao = 'direcao';
    classificacao.requer_resposta = false;
    classificacao.tags.push('equipe_perguntou');
  }

  if ((classificacao.indicadores.pediu_material || classificacao.indicadores.pediu_call) && !isEquipe) {
    classificacao.tipo_interacao = 'solicitacao';
    classificacao.requer_acao_equipe = true;
    classificacao.requer_resposta = true;
    classificacao.urgencia_resposta = '24h';
    classificacao.prioridade = 'alta';
    classificacao.tags.push('solicitacao');
  }

  if ((classificacao.indicadores.mencionou_dificuldade || classificacao.indicadores.demonstrou_travamento) && !isEquipe) {
    classificacao.tipo_interacao = 'bloqueio';
    classificacao.requer_resposta = true;
    classificacao.urgencia_resposta = '24h';
    classificacao.prioridade = 'alta';
    classificacao.score_engajamento = 4;
    classificacao.tags.push('bloqueio');
  }

  if (classificacao.indicadores.planejou_acao && classificacao.tipo_interacao === 'mensagem') {
    classificacao.tipo_interacao = 'direcao'; classificacao.tags.push('planejamento');
  }

  // Sentimentos
  if (classificacao.indicadores.celebrou_vitoria) { classificacao.sentimento = 'positivo'; classificacao.energia = 'alto'; }
  if (classificacao.indicadores.frustrado) { classificacao.sentimento = 'negativo'; classificacao.energia = 'baixo'; }
  if (classificacao.indicadores.sinalizou_desistencia) {
    classificacao.sentimento = 'negativo'; classificacao.energia = 'critico';
    classificacao.prioridade = 'urgente'; classificacao.tags.push('risco');
  }

  // Categorias
  if (classificacao.indicadores.reportou_venda || classificacao.indicadores.mencionou_lead) classificacao.categoria = 'vendas';
  if (classificacao.indicadores.publicou_conteudo || classificacao.indicadores.planejou_conteudo) classificacao.categoria = 'marketing';
  if (classificacao.indicadores.mencionou_valores) classificacao.categoria = 'financeiro';
  if (classificacao.indicadores.pediu_material) { classificacao.categoria = 'operacional'; classificacao.tags.push('material'); }
  if (classificacao.indicadores.mencionou_lead) classificacao.tags.push('lead');
  if (classificacao.indicadores.publicou_conteudo) classificacao.tags.push('conteudo');
  if (classificacao.indicadores.mencionou_valores) classificacao.tags.push('metricas');
}

// Acoes sugeridas (so pra msgs nao descartaveis)
if (!descartavel) {
  if (classificacao.requer_resposta && classificacao.eh_pergunta_real) classificacao.acoes_sugeridas.push('responder_pergunta');
  if (classificacao.indicadores.pediu_material) classificacao.acoes_sugeridas.push('enviar_material');
  if (classificacao.indicadores.pediu_call) classificacao.acoes_sugeridas.push('agendar_call');
  if (classificacao.indicadores.mencionou_dificuldade || classificacao.indicadores.demonstrou_travamento) classificacao.acoes_sugeridas.push('call_desbloqueio');
  if (classificacao.indicadores.reportou_venda) classificacao.acoes_sugeridas.push('parabenizar');
  if (classificacao.indicadores.planejou_acao) classificacao.acoes_sugeridas.push('acompanhar_execucao');
  if (classificacao.indicadores.sinalizou_desistencia || classificacao.indicadores.questionou_metodologia) classificacao.acoes_sugeridas.push('call_urgente');
}

const mapaTipoParaIntencao = { 'duvida': 'questionar', 'solicitacao': 'solicitar', 'reporte': 'relatar', 'celebracao': 'compartilhar', 'bloqueio': 'reclamar', 'direcao': 'compartilhar', 'social': 'social' };
classificacao.intencao_primaria = mapaTipoParaIntencao[classificacao.tipo_interacao] || 'compartilhar';

const registro = {
  mentorado_id: parseInt(mentorado.id),
  message_id: message.message_id,
  conteudo: txtLimpo,
  contexto_completo: JSON.stringify({ original: content, transcription: item.json.transcription || null, image_analysis: item.json.image_analysis || null, doc_analysis: item.json.doc_analysis || null }),
  timestamp: message.timestamp,
  sender_name: message.sender_name || 'Desconhecido',
  sender_phone: message.sender_phone || null,
  is_group: message.is_group || false,
  chat_id: message.chat_id || null,
  message_type: message.message_type || 'conversation',
  eh_equipe: classificacao.eh_equipe,
  autor_identificado: classificacao.autor_identificado,
  tipo_interacao: classificacao.tipo_interacao,
  categoria: classificacao.categoria,
  prioridade: classificacao.prioridade,
  sentimento: classificacao.sentimento,
  intencao_primaria: classificacao.intencao_primaria,
  score_engajamento: classificacao.score_engajamento,
  requer_resposta: classificacao.requer_resposta,
  requer_acao_equipe: classificacao.requer_acao_equipe,
  urgencia_resposta: classificacao.urgencia_resposta,
  indicadores: JSON.stringify(classificacao.indicadores),
  valores_extraidos: JSON.stringify(classificacao.valores_extraidos),
  mencoes: JSON.stringify(classificacao.mencoes),
  tags: classificacao.tags.length > 0 ? classificacao.tags : null,
  acoes_sugeridas: classificacao.acoes_sugeridas.length > 0 ? classificacao.acoes_sugeridas : null,
  classification: JSON.stringify(classificacao)
};

return [{json: registro}];
